}(this, function() {
    'use strict';

    var savedRuns = [];
    var nextRunId = 1;

    function clone(value) {
        if (value === undefined) {
            return undefined;
        }
        return JSON.parse(JSON.stringify(value));
    }

    function toMetricNumber(value) {
        if (typeof value !== 'number' || !isFinite(value)) {
            return null;
        }
        return value;
    }

    function normalizeRunId(id) {
        if (typeof id === 'number' && isFinite(id) && Math.floor(id) === id) {
            return id;
        }
        if (typeof id === 'string' && /^\d+$/.test(id)) {
            return parseInt(id, 10);
        }
        return null;
    }

    function normalizeTimestamp(timestamp) {
        if (!timestamp) {
            return new Date().toISOString();
        }
        if (timestamp instanceof Date) {
            return timestamp.toISOString();
        }
        return String(timestamp);
    }

    function captureMetrics(runData) {
        runData = runData || {};

        var nodesExplored = toMetricNumber(runData.nodesExplored);
        if (nodesExplored === null) {
            if (Array.isArray(runData.exploredNodes)) {
                nodesExplored = runData.exploredNodes.length;
            } else if (Array.isArray(runData.visitedNodes)) {
                nodesExplored = runData.visitedNodes.length;
            } else {
                nodesExplored = 0;
            }
        }

        var pathLength = toMetricNumber(runData.pathLength);
        if (pathLength === null) {
            pathLength = Array.isArray(runData.path) ? runData.path.length : 0;
        }

        var timeMs = toMetricNumber(runData.timeMs);
        if (timeMs === null) {
            timeMs = toMetricNumber(runData.time);
        }
        if (timeMs === null) {
            timeMs = 0;
        }

        return {
            nodesExplored: nodesExplored,
            pathLength: pathLength,
            timeMs: timeMs
        };
    }

    function saveRun(run) {
        if (!run || typeof run !== 'object') {
            throw new Error('A run object is required');
        }

        var metricsSource = run.metrics && typeof run.metrics === 'object' ? run.metrics : run;
        var record = {
            id: nextRunId++,
            algorithm: run.algorithm || 'Unknown',
            mapState: clone(run.mapState || {}),
            metrics: captureMetrics(metricsSource),
            timestamp: normalizeTimestamp(run.timestamp)
        };

        savedRuns.push(record);
        return clone(record);
    }

    function getSavedRuns() {
        return clone(savedRuns);
    }

    function clearRuns() {
        savedRuns.length = 0;
        nextRunId = 1;
    }

    function compareRuns(runIds) {
        if (!Array.isArray(runIds)) {
            throw new Error('runIds must be an array');
        }

        var seen = {};
        var selectedRuns = runIds.map(function(rawId) {
            var id = normalizeRunId(rawId);
            var i;

            if (id === null) {
                throw new Error('Invalid run id: ' + rawId);
            }
            if (seen[id]) {
                throw new Error('Cannot compare duplicate run id: ' + id);
            }
            seen[id] = true;

            for (i = 0; i < savedRuns.length; i += 1) {
                if (savedRuns[i].id === id) {
                    return savedRuns[i];
                }
            }
