        var differences = {};

        for (var i = 1; i < selectedRuns.length; i += 1) {
            var run = selectedRuns[i];
            differences[run.id] = {
                nodesExplored: run.metrics.nodesExplored - base.metrics.nodesExplored,
                pathLength: run.metrics.pathLength - base.metrics.pathLength,
                timeMs: run.metrics.timeMs - base.metrics.timeMs
