var should = require('should');
var scenarioScorer = require('../visual/scenario');

describe('Scenario Scorer', function() {
    beforeEach(function() {
        scenarioScorer.clearRuns();
    });

    describe('captureMetrics(runData)', function() {
        it('captures metrics from explored/path arrays and timeMs', function() {
            var metrics = scenarioScorer.captureMetrics({
                exploredNodes: [[0, 0], [0, 1], [1, 1], [2, 1]],
                path: [[0, 0], [0, 1], [1, 1]],
                timeMs: 12.6
            });

            metrics.should.eql({
                nodesExplored: 4,
                pathLength: 3,
                timeMs: 12.6
            });
        });

        it('prefers explicit numeric metrics fields when provided', function() {
            var metrics = scenarioScorer.captureMetrics({
                nodesExplored: 99,
                pathLength: 10,
                timeMs: 8,
                exploredNodes: [[0, 0]],
                path: [[0, 0]]
            });

            metrics.should.eql({
                nodesExplored: 99,
                pathLength: 10,
                timeMs: 8
            });
        });

        it('supports visitedNodes and time fallback fields', function() {
            var metrics = scenarioScorer.captureMetrics({
                visitedNodes: [[0, 0], [1, 0], [2, 0]],
                path: [[0, 0], [1, 0]],
                time: 4
            });

            metrics.should.eql({
                nodesExplored: 3,
                pathLength: 2,
                timeMs: 4
            });
        });
    });

    describe('saveRun/getSavedRuns/clearRuns', function() {
        it('saves runs with id and timestamp and returns copies from store', function() {
            var saved = scenarioScorer.saveRun({
                algorithm: 'A*',
                mapState: {width: 2, height: 2, matrix: [[0, 1], [0, 0]]},
                metrics: {nodesExplored: 7, pathLength: 4, timeMs: 1.2},
                timestamp: '2026-04-15T00:00:00.000Z'
            });

            saved.should.have.properties('id', 'algorithm', 'mapState', 'metrics', 'timestamp');
            saved.algorithm.should.equal('A*');

            var runs = scenarioScorer.getSavedRuns();
            runs.should.have.length(1);
            runs[0].should.eql(saved);

            runs[0].algorithm = 'MUTATED';
            scenarioScorer.getSavedRuns()[0].algorithm.should.equal('A*');
        });

        it('clears all saved runs', function() {
            scenarioScorer.saveRun({algorithm: 'A*', mapState: {}, metrics: {nodesExplored: 1, pathLength: 1, timeMs: 1}});
            scenarioScorer.saveRun({algorithm: 'Dijkstra', mapState: {}, metrics: {nodesExplored: 2, pathLength: 1, timeMs: 2}});

            scenarioScorer.getSavedRuns().should.have.length(2);
            scenarioScorer.clearRuns();
            scenarioScorer.getSavedRuns().should.eql([]);
        });

        it('captures metrics from a raw run when metrics is omitted', function() {
            var saved = scenarioScorer.saveRun({
                algorithm: 'A*',
                mapState: { id: 'map-raw' },
                exploredNodes: [[0, 0], [1, 0], [2, 0]],
                path: [[0, 0], [1, 0]],
                timeMs: 3
            });

            saved.metrics.should.eql({
                nodesExplored: 3,
                pathLength: 2,
                timeMs: 3
            });
        });
    });

    describe('compareRuns(runIds)', function() {
        it('compares two or more runs and returns metric deltas against first run', function() {
            var runA = scenarioScorer.saveRun({
                algorithm: 'A*',
                mapState: {id: 'map-1'},
                metrics: {nodesExplored: 10, pathLength: 6, timeMs: 5}
            });
            var runB = scenarioScorer.saveRun({
                algorithm: 'Dijkstra',
                mapState: {id: 'map-1'},
                metrics: {nodesExplored: 14, pathLength: 6, timeMs: 9}
            });
            var runC = scenarioScorer.saveRun({
                algorithm: 'BreadthFirst',
                mapState: {id: 'map-2'},
                metrics: {nodesExplored: 8, pathLength: 7, timeMs: 7}
            });

            var comparison = scenarioScorer.compareRuns([runA.id, runB.id, runC.id]);
            comparison.baseRunId.should.equal(runA.id);
            comparison.runs.should.have.length(3);

            comparison.differences[runB.id].should.eql({
                nodesExplored: 4,
                pathLength: 0,
                timeMs: 4
            });
            comparison.differences[runC.id].should.eql({
                nodesExplored: -2,
                pathLength: 1,
                timeMs: 2
            });
        });

        it('throws when fewer than two valid runs are provided', function() {
            var run = scenarioScorer.saveRun({
                algorithm: 'A*',
                mapState: {},
                metrics: {nodesExplored: 1, pathLength: 1, timeMs: 1}
            });

            (function() {
                scenarioScorer.compareRuns([run.id]);
            }).should.throw();
        });

        it('throws when a requested run id does not exist', function() {
            var runA = scenarioScorer.saveRun({
                algorithm: 'A*',
                mapState: {},
                metrics: {nodesExplored: 2, pathLength: 2, timeMs: 2}
            });
            var runB = scenarioScorer.saveRun({
                algorithm: 'Dijkstra',
                mapState: {},
                metrics: {nodesExplored: 3, pathLength: 2, timeMs: 4}
            });

            (function() {
                scenarioScorer.compareRuns([runA.id, 999, runB.id]);
            }).should.throw(/not found/);
        });

        it('throws when duplicate run ids are provided', function() {
            var run = scenarioScorer.saveRun({
                algorithm: 'A*',
                mapState: {},
                metrics: {nodesExplored: 2, pathLength: 2, timeMs: 2}
            });
            scenarioScorer.saveRun({
                algorithm: 'Dijkstra',
                mapState: {},
                metrics: {nodesExplored: 3, pathLength: 2, timeMs: 4}
            });

            (function() {
                scenarioScorer.compareRuns([run.id, run.id]);
            }).should.throw(/duplicate/);
        });
    });
});

var scenario = require('../visual/scenario');

describe('Scenario persistence', function() {
    var gridState;

    beforeEach(function() {
        gridState = {
            width: 15,
            height: 15,
            walls: [
                [1, 1],
                [2, 2],
                [3, 4]
            ],
            start: [0, 0],
            end: [14, 14]
        };
    });

    it('should save scenario as JSON string with required fields', function() {
        var saved = scenario.saveScenario(gridState);
        saved.should.be.a.String();

        var parsed = JSON.parse(saved);
        parsed.width.should.equal(15);
        parsed.height.should.equal(15);
        parsed.walls.should.eql(gridState.walls);
        parsed.start.should.eql(gridState.start);
        parsed.end.should.eql(gridState.end);
    });

    it('should load scenario from saved JSON without data loss', function() {
        var saved = scenario.saveScenario(gridState);
        var loaded = scenario.loadScenario(saved);
        loaded.should.eql(gridState);
    });

    it('should load scenario from parsed JSON object input', function() {
        var parsed = JSON.parse(scenario.saveScenario(gridState));
        var loaded = scenario.loadScenario(parsed);

        loaded.should.eql(gridState);
        loaded.should.not.equal(parsed);
    });

    it('should reject invalid scenario JSON format', function() {
        (function() {
            scenario.loadScenario('{"width":15}');
        }).should.throw();

        (function() {
            scenario.loadScenario('{"width":15,"height":15,"walls":[],"start":[0],"end":[14,14]}');
        }).should.throw();

        (function() {
            scenario.loadScenario('{"width":15,"height":15,"walls":[[15,0]],"start":[0,0],"end":[14,14]}');
        }).should.throw();

        (function() {
            scenario.loadScenario('{"width":15,"height":15,"walls":[[0,0]],"start":[0,0],"end":[14,14]}');
        }).should.throw();

        (function() {
            scenario.loadScenario('{"width":15,"height":15,"walls":[[14,14]],"start":[0,0],"end":[14,14]}');
        }).should.throw();
    });
});

describe('Scenario presets', function() {
    it('should list built-in preset names', function() {
        scenario.getPresets().should.eql([
            'Empty',
            'Maze',
            'Spiral',
            'Bottleneck',
            'Random'
        ]);
    });

    it('should load each preset as a valid 15x15 scenario', function() {
        scenario.getPresets().forEach(function(name) {
            var preset = scenario.loadPreset(name);
            preset.width.should.equal(15);
            preset.height.should.equal(15);
            preset.start.length.should.equal(2);
            preset.end.length.should.equal(2);
            preset.start[0].should.be.within(0, 14);
            preset.start[1].should.be.within(0, 14);
            preset.end[0].should.be.within(0, 14);
            preset.end[1].should.be.within(0, 14);

            // Should already pass the same validation as imported JSON.
            scenario.loadScenario(JSON.stringify(preset)).should.eql(preset);
        });
    });

    it('should generate random preset with approximately 30% walls', function() {
        var preset = scenario.loadPreset('Random');
        var density = preset.walls.length / (preset.width * preset.height);
        density.should.be.above(0.15);
        density.should.be.below(0.45);
    });

    it('should throw for unknown preset name', function() {
        (function() {
            scenario.loadPreset('NotARealPreset');
        }).should.throw();
    });

    it('should return independent preset instances', function() {
        var first = scenario.loadPreset('Maze');
        first.walls.push([0, 1]);

        var second = scenario.loadPreset('Maze');
        second.walls.should.not.eql(first.walls);
    });
});

var should = require('should');
var scenarioScorer = require('../../visual/scenario');

