            timestamp: '2026-04-15T00:00:00.000Z'
        });
        scenarioScorer.saveRun({
            algorithm: 'DijkstraFinder',
            mapState: { width: 2, height: 2, walls: [[1, 0]] },
            metrics: { nodesExplored: 7, pathLength: 3, timeMs: 2.2 },
            timestamp: '2026-04-15T00:00:01.000Z'
        });

        var runs = scenarioScorer.getSavedRuns();
        runs.should.have.length(2);
        runs[0].should.have.properties('id', 'algorithm', 'mapState', 'metrics', 'timestamp');
