        scenarioScorer.clearRuns();
        scenarioScorer.getSavedRuns().should.eql([]);
    });

    it('compares two or more saved runs and returns metric deltas', function() {
        var base = scenarioScorer.saveRun({
            algorithm: 'AStarFinder',
            mapState: {},
            metrics: { nodesExplored: 10, pathLength: 6, timeMs: 4 }
        });
        var other = scenarioScorer.saveRun({
            algorithm: 'BestFirstFinder',
            mapState: {},
            metrics: { nodesExplored: 8, pathLength: 7, timeMs: 3 }
        });

        var comparison = scenarioScorer.compareRuns([base.id, other.id]);
        comparison.baseRunId.should.equal(base.id);
        comparison.runs.should.have.length(2);
        comparison.differences[other.id].should.eql({
            nodesExplored: -2,
            pathLength: 1,
            timeMs: -1
        });
    });

    it('throws when comparing duplicate or unknown run ids', function() {
        var runA = scenarioScorer.saveRun({
            algorithm: 'AStarFinder',
            mapState: {},
            metrics: { nodesExplored: 1, pathLength: 1, timeMs: 1 }
        });
        var runB = scenarioScorer.saveRun({
            algorithm: 'DijkstraFinder',
            mapState: {},
            metrics: { nodesExplored: 2, pathLength: 1, timeMs: 2 }
        });

        (function() {
            scenarioScorer.compareRuns([runA.id, runA.id]);
        }).should.throw(/duplicate/);

        (function() {
            scenarioScorer.compareRuns([runA.id, 999, runB.id]);
        }).should.throw(/not found/);
    });

    it('rejects non-integer run ids in comparisons', function() {
        var run = scenarioScorer.saveRun({
            algorithm: 'AStarFinder',
            mapState: {},
            metrics: { nodesExplored: 1, pathLength: 1, timeMs: 1 }
        });
        scenarioScorer.saveRun({
            algorithm: 'DijkstraFinder',
            mapState: {},
            metrics: { nodesExplored: 2, pathLength: 1, timeMs: 2 }
        });

        (function() {
            scenarioScorer.compareRuns([run.id, 1.5]);
        }).should.throw(/Invalid run id/);
    });

    it('normalizes Date timestamps to ISO strings when saving runs', function() {
        var timestamp = new Date('2026-04-15T00:00:00.000Z');
        var run = scenarioScorer.saveRun({
            algorithm: 'AStarFinder',
            mapState: {},
