function createStateMachine() {
    function normalizeFrom(from) {
        if (from === '*') {
            return '*';
        }
        return Array.isArray(from) ? from : [from];
    }

    var api = {
        ASYNC: 'ASYNC',
        create: function(definition) {
            var machine = {
                current: definition.initial,
                transition: null,
                is: function(state) {
                    return this.current === state;
                },
                can: function(eventName) {
                    var event = eventsByName[eventName];
                    if (!event) {
                        return false;
                    }
                    if (event.from === '*') {
                        return true;
                    }
                    return event.from.indexOf(this.current) !== -1;
                }
            };
            var eventsByName = {};

            definition.events.forEach(function(event) {
                eventsByName[event.name] = {
                    from: normalizeFrom(event.from),
                    to: event.to
                };
                machine[event.name] = function() {
                    var args = Array.prototype.slice.call(arguments);
                    var from = machine.current;
                    var eventDef = eventsByName[event.name];
                    var leaveHandler = machine['onleave' + from];
                    var eventHandler = machine['on' + event.name];
                    var enterHandler = machine['on' + eventDef.to];

                    if (!machine.can(event.name)) {
                        throw new Error('invalid transition for ' + event.name + ' from ' + from);
                    }

                    machine.transition = function() {
                        machine.current = eventDef.to;
                        if (enterHandler) {
                            enterHandler.apply(machine, [event.name, from, eventDef.to].concat(args));
                        }
                    };

                    if (leaveHandler && leaveHandler.apply(machine, [event.name, from, eventDef.to].concat(args)) === api.ASYNC) {
                        return;
                    }

                    if (eventHandler) {
                        eventHandler.apply(machine, [event.name, from, eventDef.to].concat(args));
                    }

                    machine.transition();
                };
            });

            return machine;
        }
    };

    return api;
}

function loadController() {
    var source = fs.readFileSync(path.resolve(__dirname, '../../visual/js/controller.js'), 'utf8');
    var buttonRecords = [];
    var jqProxy = function(fn, ctx) {
        return function() {
            return fn.apply(ctx, arguments);
        };
    };
    var context = {
        console: { log: function() {}, error: function() {} },
        StateMachine: createStateMachine(),
        setTimeout: function(cb) { cb(); },
        window: { performance: { now: function() { return 10; } } },
        performance: { now: function() { return 10; } },
        Date: Date,
        PF: {
            Node: function Node() {},
            Grid: function Grid() {},
            Util: { pathLength: function() { return 0; } }
        },
        View: {
            nodeColorizeEffect: { duration: 1 },
            supportedOperations: ['opened', 'closed', 'tested'],
            setAttributeAt: function() {},
            clearFootprints: function() {},
            clearPath: function() {},
            clearBlockedNodes: function() {},
            showStats: function() {},
            drawPath: function() {},
            toGridCoordinate: function(x, y) { return [x, y]; },
            setStartPos: function() {},
            setEndPos: function() {}
        },
        $: function() {
            return {
                eq: function(index) {
                    if (!buttonRecords[index]) {
                        buttonRecords[index] = {
                            textValue: null,
                            disabled: false,
                            callback: null,
                            text: function(value) { this.textValue = value; return this; },
                            unbind: function() { return this; },
                            click: function(cb) { this.callback = cb; return this; },
                            removeAttr: function() { this.disabled = false; return this; },
                            attr: function(opts) { if (opts && opts.disabled) { this.disabled = true; } return this; }
                        };
                    }
                    return buttonRecords[index];
                },
                mousedown: function() { return this; },
                mousemove: function() { return this; },
                mouseup: function() { return this; },
                bind: function() { return this; },
                width: function() { return 1000; },
                height: function() { return 500; }
            };
        }
    };

    context.$.extend = function(target, src) {
        Object.keys(src).forEach(function(key) {
            target[key] = src[key];
        });
        return target;
    };
    context.$.proxy = jqProxy;
    context.$.each = function(items, cb) {
        Array.prototype.forEach.call(items, function(item, idx) {
            cb(idx, item);
        });
    };

    vm.runInNewContext(source, context, { filename: 'controller.js' });
    context.Controller.$buttons = context.$('.control_button');

    return {
        Controller: context.Controller,
        View: context.View,
        PF: context.PF,
        buttonRecords: buttonRecords
    };
}

describe('visual/controller', function() {
    it('should expose expected transition guards', function() {
        var loaded = loadController();
        var controller = loaded.Controller;

        controller.can('start').should.equal(false);

        controller.current = 'ready';
        controller.can('start').should.equal(true);
        controller.can('pause').should.equal(false);

        controller.current = 'searching';
        controller.can('pause').should.equal(true);
        controller.can('finish').should.equal(true);

        controller.current = 'finished';
        controller.can('modify').should.equal(true);
        controller.can('clear').should.equal(true);
    });

    it('should map button labels and callbacks per state', function() {
        var loaded = loadController();
        var controller = loaded.Controller;
        var buttons = loaded.buttonRecords;

        controller.onready();
        buttons[0].textValue.should.equal('Start Search');
        buttons[1].disabled.should.equal(true);
        buttons[2].textValue.should.equal('Clear Walls');

        controller.onsearching();
        buttons[0].textValue.should.equal('Restart Search');
        buttons[1].textValue.should.equal('Pause Search');

        controller.onpaused();
        buttons[0].textValue.should.equal('Resume Search');
        buttons[1].textValue.should.equal('Cancel Search');

        controller.onfinished();
        buttons[1].textValue.should.equal('Clear Path');

        controller.onmodified();
        buttons[0].textValue.should.equal('Start Search');
        buttons[1].textValue.should.equal('Clear Path');
    });

    it('should record operations via hooked PF.Node setters', function() {
        var loaded = loadController();
        var controller = loaded.Controller;
        var Node = loaded.PF.Node;
        var node;

        controller.hookPathFinding();

        node = new Node();
        node.x = 2;
        node.y = 3;
        node.opened = true;
        node.closed = true;
        node.tested = true;

        should(JSON.parse(JSON.stringify(controller.operations))).eql([
            { x: 2, y: 3, attr: 'opened', value: true },
            { x: 2, y: 3, attr: 'closed', value: true },
            { x: 2, y: 3, attr: 'tested', value: true }
        ]);
    });

    it('should step supported operations and finish when queue is depleted', function() {
        var loaded = loadController();
        var controller = loaded.Controller;
        var viewCalls = [];
        var finished = false;

        loaded.View.setAttributeAt = function(x, y, attr, value) {
            viewCalls.push([x, y, attr, value]);
        };
        controller.finish = function() {
            finished = true;
        };

        controller.operations = [
            { x: 0, y: 0, attr: 'parent', value: null },
            { x: 1, y: 2, attr: 'opened', value: true }
        ];
        controller.step();

        should(viewCalls).eql([[1, 2, 'opened', true]]);

        controller.operations = [];
        controller.step();
        finished.should.equal(true);
    });

    it('should route mouse interactions for drag draw and erase flows', function() {
        var loaded = loadController();
        var controller = loaded.Controller;
        var transitions = [];
        var walkable = { '1,1': true, '2,2': false, '4,4': true };

        controller.grid = {
            isWalkableAt: function(x, y) {
                return walkable[x + ',' + y] !== false;
            }
        };
        controller.startX = 0;
        controller.startY = 0;
        controller.endX = 3;
        controller.endY = 3;
        controller.can = function(name) {
            return ['dragStart', 'dragEnd', 'drawWall', 'eraseWall', 'rest'].indexOf(name) !== -1;
        };
        controller.dragStart = function() { transitions.push('dragStart'); };
        controller.dragEnd = function() { transitions.push('dragEnd'); };
        controller.drawWall = function(x, y) { transitions.push('drawWall:' + x + ',' + y); };
        controller.eraseWall = function(x, y) { transitions.push('eraseWall:' + x + ',' + y); };
        controller.rest = function() { transitions.push('rest'); };
        controller.setWalkableAt = function(x, y, value) { transitions.push('setWalkableAt:' + x + ',' + y + ':' + value); };
        controller.setStartPos = function(x, y) { transitions.push('setStart:' + x + ',' + y); };
        controller.setEndPos = function(x, y) { transitions.push('setEnd:' + x + ',' + y); };

        controller.mousedown({ pageX: 0, pageY: 0 });
        controller.mousedown({ pageX: 3, pageY: 3 });
        controller.mousedown({ pageX: 1, pageY: 1 });
        controller.mousedown({ pageX: 2, pageY: 2 });

        controller.current = 'drawingWall';
        controller.mousemove({ pageX: 4, pageY: 4 });

        controller.current = 'erasingWall';
        controller.mousemove({ pageX: 1, pageY: 1 });

        controller.current = 'draggingStart';
        controller.mousemove({ pageX: 4, pageY: 4 });

        controller.current = 'draggingEnd';
        controller.mousemove({ pageX: 4, pageY: 4 });

        controller.mouseup({});

        transitions.should.containEql('dragStart');
        transitions.should.containEql('dragEnd');
        transitions.should.containEql('drawWall:1,1');
        transitions.should.containEql('eraseWall:2,2');
        transitions.should.containEql('setWalkableAt:4,4:false');
        transitions.should.containEql('setWalkableAt:1,1:true');
        transitions.should.containEql('setStart:4,4');
        transitions.should.containEql('setEnd:4,4');
        transitions.should.containEql('rest');
    });
});

