function createRect() {
    return {
        attrs: { fill: 'white' },
        removed: false,
        attr: function(a, b) {
            if (typeof a === 'string') {
                if (typeof b === 'undefined') {
                    return this.attrs[a];
                }
                this.attrs[a] = b;
                return this;
            }
            Object.keys(a).forEach(function(key) {
                this.attrs[key] = a[key];
            }, this);
            return this;
        },
        animate: function(a) {
            return this.attr(a);
        },
        toFront: function() { return this; },
        clone: function() {
            var copy = createRect();
            copy.attrs = Object.assign({}, this.attrs);
            return copy;
        },
        remove: function() {
            this.removed = true;
        }
    };
}

function loadView() {
    var source = fs.readFileSync(path.resolve(__dirname, '../../visual/js/view.js'), 'utf8');

    var stats = {
        textValue: '',
