        pathValue: null,
        setSize: function(w, h) { this.width = w; this.height = h; },
        rect: function() { return createRect(); },
        path: function(value) {
            this.pathValue = value;
            return {
                attrs: {},
                attr: function(style) { this.attrs = style; return this; },
                remove: function() { this.removed = true; }
            };
        }
    };

    var context = {
        console: { log: function() {}, error: function() {} },
        setTimeout: function(cb) { cb(); },
        async: {
            series: function(tasks, done) {
                tasks.forEach(function(task) {
                    task(function() {});
                });
                done();
            }
        },
        Raphael: function() {
            return paper;
        },
        $: function(selector) {
            if (selector === '#stats') {
                return stats;
            }
            return {
                show: function() { return this; },
                html: function() { return this; }
            };
        }
    };

    vm.runInNewContext(source, context, { filename: 'view.js' });

    return {
        View: context.View,
        paper: paper,
